813	    .filter((e) => (e.method ?? 'GET') === 'GET' && !/_scenario|:/.test(e.routePath ?? e.name ?? ''));
814	  report.check(
815	    'the app declares ≥1 of its OWN GET routes (what its pages fetch)',
816	    getRoutes.length >= 1,
817	    getRoutes.map((e) => e.routePath ?? e.name).join(', ') || 'none',
818	  );
819	
820	  /** A page fetches JSON. An HTML shell with status 200 is a BROKEN route, not a passing one. */
821	  const isRealJson = (res) => {
822	    if (res.status !== 200) return false;
823	    const raw = typeof res.body === 'string' ? res.body : JSON.stringify(res.body ?? '');
824	    if (/^\s*<!doctype|^\s*<html/i.test(raw)) return false; // the SPA fallback answered, not the app
825	    if (typeof res.body !== 'object' || res.body === null) return false;
826	    return JSON.stringify(res.body).length > 20;
827	  };
828	
829	  let realData = 0;
830	  for (const e of getRoutes.slice(0, 6)) {
831	    const route = String(e.routePath ?? e.name ?? '').replace(/^\//, '');
832	    if (!route) continue;
833	    const res = await pod.appApi(PROJECT, route, undefined, 'GET').catch((err) => ({ status: 0, body: String(err) }));
834	    const raw = typeof res.body === 'string' ? res.body : JSON.stringify(res.body ?? '');
835	    const ok = isRealJson(res);
836	    if (ok) realData++;
837	    report.check(
838	      `the app's own route GET /${PROJECT}/api/${route} → 200 with real JSON (the layer the PAGE fetches)`,
839	      ok,
840	      `status ${res.status}: ${/^\s*<!doctype/i.test(raw) ? 'HTML SHELL — the app API is not served at this URL' : raw.slice(0, 140)}`,
841	    );
842	  }
843	  const page = await pod.appPage(PROJECT).catch(() => ({ status: 0, body: '' }));
844	  const html = String(page.body ?? '');
845	  report.check('the served page is real HTML (200 + a mounted root)', page.status === 200 && /<!doctype/i.test(html), `status ${page.status}, ${html.length} bytes`);
846	  // …and its bundle must actually RESOLVE. A shell whose <script src> 404s renders a blank page,
847	  // which is an anti-expectation — and it is invisible to every check that stops at "200 + doctype".
848	  const assetRefs = [...html.matchAll(/(?:src|href)="([^"]*assets\/[^"]+)"/g)].map((m) => m[1]);
849	  const assetChecks = [];
850	  const pageUrl = `${pod.appOrigin(PROJECT)}/`;
851	  for (const ref of assetRefs.slice(0, 4)) {
852	    // Resolve EXACTLY as the browser does against the page URL: a root-absolute `/assets/x.js`
853	    // resolves against the ORIGIN (dropping the `/<project>/` mount), a relative `./assets/x.js`
854	    // against the app's directory. Rebasing it under the project by hand is what hides the bug.
855	    const url = new URL(ref, pageUrl).toString();
856	    const r = await pod.reqAbs('GET', url).catch(() => ({ status: 0 }));
857	    assetChecks.push({ ref, url, status: r.status });
858	  }
859	  report.check(
860	    "the served shell's own bundle RESOLVES as a BROWSER resolves it (a 404 here = a blank app)",
861	    assetChecks.length > 0 && assetChecks.every((a) => a.status === 200),
862	    assetChecks.map((a) => `${a.ref} → ${new URL(a.url).pathname} → ${a.status}`).join(' · ') || 'no asset refs in the shell',
863	  );
864	
865	  // Hand the browser pass everything it needs (chrome-devtools MCP, driven outside the runner).
866	  const target = {
867	    appUrl: `${pod.appOrigin(PROJECT)}/`,
868	    chatOrigin: pod.base,
869	    projectId: PROJECT,
870	    userId: user.userId,
871	    email: user.email,
872	    accessToken: user.token,
873	    note: 'Set localStorage.lmthing_session on BOTH origins AND the access_token cookie on the app origin.',
874	  };
875	  mkdirSync(RESULTS, { recursive: true });
876	  writeFileSync(`${RESULTS}/browser-target.json`, JSON.stringify(target, null, 2));
877	  console.log(`\n🌐 BROWSER PASS → ${target.appUrl}   (session written to ${RESULTS}/browser-target.json)`);
878	  cp.acts.XIV = { passed: report.stepPassed, appUrl: target.appUrl, realDataRoutes: realData };
879	  saveCheckpoint(cp);
880	}
881	
882	// ═══ WHOLE-SESSION INVARIANTS ══════════════════════════════════════════════════
883	report.step(
884	  'Whole-session invariants',
885	  'zero UNRECOVERED eval/typecheck errors across the whole session (recovered ones are the retry ' +
886	    'surface — a metric, not a failure)',
887	);
888	const whole = thing.turn(0, 0);
889	const fatal = unrecovered(whole);
890	report.check('0 unrecovered eval/typecheck errors across the session', fatal.length === 0, fatal.map((e) => `${e.type}: ${e.message}`).join(' | ') || 'none');
891	report.metric('recovered eval/typecheck errors (retry surface)', whole.errors.length - fatal.length);
892	const stats = thing.stats();
893	report.metric('LLM calls', stats.llmCalls);
894	report.metric('delegates', stats.delegates.length);
895	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
896	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
897	
898	report.save(`${RESULTS}/report.md`);
899	report.saveTrace(`${RESULTS}/trace.json`, thing);
900	cp.done = true;
901	cp.summary = report.summary();
902	saveCheckpoint(cp);
903	console.log(JSON.stringify(report.summary(), null, 2));
904	process.exit(report.passed ? 0 : 1);
