1	/**
2	 * Pod HTTP client — the compute pod IS the app (see sdk/org/libs/cli/src/server/serve.ts).
3	 *
4	 * The pod itself does no auth: Envoy validates the gateway JWT at the edge and routes on the
5	 * `sub` claim to `lmthing.user-<id>.svc`. So every call here just carries the bearer token and
6	 * talks to the chat origin. Locally (`lmthing serve`) pass base=http://localhost:8080 and no token.
7	 */
8	
9	/**
10	 * A pod that is scaling from zero, rolling a new image, or sitting behind a blipping gateway does
11	 * not always answer with a *response* — the connection itself fails (undici's 10s
12	 * `ConnectTimeoutError`, `ECONNRESET`, `socket hang up`, a DNS `EAI_AGAIN`). Those surface as a
13	 * bare `TypeError: fetch failed`, which is NOT an HTTP status and so slipped past every
14	 * `{waking:true}`/504 retry below — one connect timeout to lmthing.chat killed a multi-hour run
15	 * with an uncaught exception. Treat a transient transport fault exactly like a `waking` answer:
16	 * back off and retry. A non-transient error (a bad URL, an aborted body) still throws at once.
17	 */
18	const TRANSIENT = /fetch failed|ConnectTimeout|UND_ERR|ECONNRESET|ECONNREFUSED|EAI_AGAIN|socket hang up|network|terminated|other side closed/i;
19	
20	export async function fetchResilient(url, init, { tries = 40, waitMs = 3000 } = {}) {
21	  for (let attempt = 0; ; attempt++) {
22	    try {
23	      return await fetch(url, init);
24	    } catch (e) {
25	      const msg = `${e?.message ?? e} ${e?.cause?.code ?? ''} ${e?.cause?.message ?? ''}`;
26	      if (!TRANSIENT.test(msg) || attempt >= tries) throw e;
27	      await new Promise((r) => setTimeout(r, waitMs));
28	    }
29	  }
30	}
31	
32	export class Pod {
33	  /**
34	   * @param {object} o
35	   * @param {string} o.base      the pod/API origin (prod: https://lmthing.chat)
36	   * @param {string} [o.token]   gateway JWT (Envoy routes on its `sub` claim)
37	   * @param {string} [o.appBase] the SERVED-APP origin. In prod the app is NOT reachable under
38	   *   `<chat>/app/<id>/` — Envoy hands `/app/*` on the chat host to the static web SPA (nginx),
39	   *   which answers a GET with the SPA *shell* (a 200 `<!doctype>` that is not the app at all —
40	   *   a scenario asserting only "200 + <!doctype" false-passes) and a POST with **405**. The app
41	   *   is root-mounted on lmthing.app (`/<project>/`, `/<project>/api/<route>` — serve.ts's
42	   *   "Project-app ROOT mount"). Locally there is no split host, so apps stay under `/app/<id>/`.
43	   */
44	  constructor({ base, token, appBase }) {
45	    this.base = base;
46	    this.token = token;
47	    this.appBase = appBase ?? process.env.LM_APP_BASE ?? (/lmthing\.chat/.test(base) ? 'https://lmthing.app' : base);
48	    /** true when the app has its own host → root mount (no `/app` prefix). */
49	    this.appRootMounted = this.appBase !== this.base;
50	  }
51	
52	  /** The origin+prefix the SERVED app actually lives at (see `appBase`). */
53	  appOrigin(projectId) {
54	    return this.appRootMounted
55	      ? `${this.appBase}/${projectId}`
56	      : `${this.base}/app/${projectId}`;
57	  }
58	
59	  /** Absolute-URL variant of `req` (the served app is on a different origin than /api/*). */
60	  async reqAbs(method, url, body) {
61	    for (let attempt = 0; ; attempt++) {
62	      const res = await fetchResilient(url, {
63	        method,
64	        headers: {
65	          ...(body !== undefined ? { 'content-type': 'application/json' } : {}),
66	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
67	        },
68	        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
69	      });
70	      const text = await res.text();
71	      let parsed = text;
72	      try {
73	        parsed = JSON.parse(text);
74	      } catch {
75	        /* html / raw */
76	      }
77	      // The activator MARKS its own response (`{waking:true}`) whatever status it uses (503/504),
78	      // so key on that marker — never on a bare 503, which for an app route is a real verdict.
79	      const waking =
80	        res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
81	      if (waking && attempt < 100) {
82	        await new Promise((r) => setTimeout(r, 3000));
83	        continue;
84	      }
85	      return { status: res.status, body: parsed };
86	    }
87	  }
88	
89	  async req(method, path, body, { raw = false } = {}) {
90	    // A scaled-to-zero pod answers with `504 {waking:true}` while the Envoy activator boots
91	    // it; that is a transient, not the endpoint's verdict. Retry idempotent-ish calls until
92	    // the pod is warm (bounded), so a read that lands on a cold pod self-heals instead of
93	    // throwing a spurious failure mid-scenario.
94	    //
95	    // The budget is minutes, not seconds. A pod that is ROLLING (a new image) or whose single
96	    // Node thread is stalled inside a long authoring turn keeps answering `waking` well past a
97	    // minute — the old 20×3s ≈ 60s gave up and threw `POST /api/sessions → 503 {waking:true}`,
98	    // killing a multi-hour run over a transient the harness was written to absorb.
99	    for (let attempt = 0; ; attempt++) {
100	      const res = await fetchResilient(`${this.base}${path}`, {
101	        method,
102	        headers: {
103	          ...(body !== undefined ? { 'content-type': 'application/json' } : {}),
104	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
105	        },
106	        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
107	      });
108	      const text = await res.text();
109	      let parsed = text;
110	      try {
111	        parsed = JSON.parse(text);
112	      } catch {
113	        /* raw text (e.g. an ASCII state tree) */
114	      }
115	      // The activator MARKS its own response (`{waking:true}`) whatever status it uses (503/504),
116	      // so key on that marker — never on a bare 503, which for an app route is a real verdict.
117	      const waking =
118	        res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
119	      if (waking && attempt < 100) {
120	        await new Promise((r) => setTimeout(r, 3000));
121	        continue;
122	      }
123	      if (!res.ok && !raw) {
124	        const err = new Error(`${method} ${path} → ${res.status}: ${text.slice(0, 400)}`);
125	        err.status = res.status;
126	        err.body = parsed;
127	        throw err;
128	      }
129	      return raw ? { status: res.status, body: parsed } : parsed;
130	    }
131	  }
132	
133	  // ── projects ────────────────────────────────────────────────────────────
134	  listProjects = () => this.req('GET', '/api/projects');
135	  createProject = (name) => this.req('POST', '/api/projects', { name });
136	  deleteProject = (id) => this.req('DELETE', `/api/projects/${id}`);
137	  listSpaces = (projectId) => this.req('GET', `/api/projects/${projectId}/spaces`);
138	  listIntegrations = (projectId) => this.req('GET', `/api/projects/${projectId}/integrations`);
139	  projectSessions = (projectId) => this.req('GET', `/api/projects/${projectId}/sessions`);
140	
141	  // ── files (the whole point: assert what the agents actually WROTE) ───────
142	  fsTree = () => this.req('GET', '/api/fs/tree');
143	  readFile = (path) => this.req('GET', `/api/fs/read?path=${encodeURIComponent(path)}`);
144	  writeFile = (path, content) => this.req('PUT', '/api/fs/write', { path, content });
145	
146	  /** Read one authored file of a project (`<project>/pages/_layout.tsx`, `api/…`) — assert what the agent WROTE. */
147	  async readProjectFile(projectId, rel) {
148	    const r = await this.readFile(`${projectId}/${rel}`).catch(() => null);
149	    return typeof r === 'string' ? r : (r?.content ?? '');
150	  }
151	
152	  // ── store ───────────────────────────────────────────────────────────────
153	  storeSpaces = () => this.req('GET', '/api/store/spaces');
154	  installSpace = (spaceId, projectId = 'user', force = false) =>
155	    this.req('POST', '/api/store/spaces/install', { spaceId, projectId, force });
156	  storeApps = () => this.req('GET', '/api/apps');
157	  installApp = (appId, projectId, force = false) =>
158	    this.req('POST', '/api/apps/install', { appId, ...(projectId ? { projectId } : {}), force });
159	
160	  // ── project-app runtime ─────────────────────────────────────────────────
161	  appManifest = (projectId) => this.req('GET', `/api/projects/${projectId}/app`);
162	  appBuild = (projectId) => this.req('POST', `/api/projects/${projectId}/app/build`);
163	  appData = (projectId, table) => this.req('GET', `/api/projects/${projectId}/app/data/${table}`);
164	  /** GET the SERVED app page — on its real origin (see `appBase`), not the SPA shell. */
165	  appPage = (projectId, path = '') => this.reqAbs('GET', `${this.appOrigin(projectId)}/${path}`);
166	
167	  // ── hooks & events ──────────────────────────────────────────────────────
168	  /** List every loaded hook across projects (`GET /api/hooks`). */
169	  listHooks = () => this.req('GET', '/api/hooks');
170	  /**
171	   * Call an app's OWN API route — the routes its pages actually fetch, on the app's real origin
172	   * (`<app-host>/<project>/api/<route>`). This is the layer the user sees: a page whose data API
173	   * returns rows can still render zeros because its own aggregation route 500s.
174	   */
175	  appApi = (projectId, route, body, method = 'POST') =>
176	    this.reqAbs(method, `${this.appOrigin(projectId)}/api/${String(route).replace(/^\//, '')}`, body);
177	  /** The one authoritative hook-run path (crond, boot catch-up and Studio all use it).
178	   *  The slug is a single path segment and may contain `:`/`@` (space hooks are
179	   *  `<spaceId>:<base>`; emitters are `@emitter:<scope>:<name>`) — encode it. */
180	  runHook = (projectId, slug) =>
181	    this.req('POST', `/api/projects/${projectId}/hooks/${encodeURIComponent(slug)}/run`, {});
182	  /** Run a cron emitter def by its pseudo-slug (`@emitter:<scope>:<name>`). */
183	  runEmitter = (projectId, scope, name) => this.runHook(projectId, `@emitter:${scope}:${name}`);
184	
185	  /**
186	   * Deliver an inbound webhook exactly as an external provider would.
187	   * `headers` carries the provider's signature headers — the pod verifies BEFORE emit.
188	   *
189	   * NOTE the bearer token: in prod the pod is reached through Envoy, which routes on the
190	   * gateway JWT's `sub` claim — without it the edge answers `401 Jwt is missing` and the
191	   * request never reaches the pod. The real public path (gateway `/api/inbound/<token>/<path>`)
192	   * is a 202 fire-and-forget broker that hides the pod's own status code, so a scenario that
193	   * needs to assert 200/401/404 + `{events:n}` must deliver to the pod directly. The pod
194	   * itself does no auth: verification is the provider signature, exactly as in production.
195	   */
196	  async inbound(path, body, headers = {}) {
197	    const payload = typeof body === 'string' ? body : JSON.stringify(body);
198	    // A scaled-to-zero pod answers the FIRST hit with `504 {waking:true}` (the Envoy
199	    // instant-wake activator) while it boots — that is not the def's real verdict. Retry
200	    // the exact same signed bytes until the woken pod actually runs verify→emit. The body
201	    // is byte-identical, but inbound dedupe only kicks in AFTER a successful verify, so a
202	    // retry of a request the pod never processed is not deduped.
203	    for (let attempt = 0; ; attempt++) {
204	      const res = await fetchResilient(`${this.base}/api/inbound/${path}`, {
205	        method: 'POST',
206	        headers: {
207	          'content-type': 'application/json',
208	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
209	          ...headers,
210	        },
211	        body: payload,
212	      });
213	      const text = await res.text();
214	      let parsed = text;
215	      try {
216	        parsed = JSON.parse(text);
217	      } catch {
218	        /* raw */
219	      }
220	      const waking = res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
221	      if (!waking || attempt >= 100) return { status: res.status, body: parsed };
222	      await new Promise((r) => setTimeout(r, 3000));
223	    }
224	  }
225	
226	  // ── uploads (chat attachments) ──────────────────────────────────────────
227	  /**
228	   * The mediaType decides the pod's ROUTE, not just a label: `image/*` goes to system-vision,
229	   * `audio/*` is transcribed at ingest, everything else goes to system-files. So a `.mp3` sent as
230	   * `application/octet-stream` is never transcribed, and a scenario asserting "a spoken-only fact
231	   * reached a row" fails for a reason that has nothing to do with the product. Every fixture type the
232	   * scenarios actually upload must be in this table.
233	   */
234	  static MEDIA_TYPES = {
235	    '.md': 'text/markdown',
236	    '.txt': 'text/plain',
237	    '.csv': 'text/csv',
238	    '.json': 'application/json',
239	    '.pdf': 'application/pdf',
240	    '.jpg': 'image/jpeg',
241	    '.jpeg': 'image/jpeg',
242	    '.png': 'image/png',
243	    '.webp': 'image/webp',
244	    '.gif': 'image/gif',
245	    '.mp3': 'audio/mpeg',
246	    '.m4a': 'audio/mp4',
247	    '.wav': 'audio/wav',
248	    '.ogg': 'audio/ogg',
249	    '.webm': 'audio/webm',
250	    '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
251	    '.xls': 'application/vnd.ms-excel',
252	    '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
253	  };
254	
255	  /**
256	   * Upload a local file as a chat attachment (the UI's "load a file" action).
257	   * `POST /api/uploads` takes base64 + mediaType and returns an AttachmentRef
258	   * (`{id, kind, mediaType, filename?, url}`) that a message then references by id.
259	   * Pair with `ThingSession.sendWithAttachments()` (WS path — HTTP /message drops attachments).
260	   *
261	   * Throws on an unknown extension rather than silently sending `application/octet-stream` — a
262	   * misrouted attachment turns a real product failure into a green test (see MEDIA_TYPES).
263	   */
264	  async upload(filePath, { mediaType, filename } = {}) {
265	    const { readFileSync } = await import('node:fs');
266	    const { basename, extname } = await import('node:path');
267	    const bytes = readFileSync(filePath);
268	    const ext = extname(filePath).toLowerCase();
269	    const mt = mediaType ?? Pod.MEDIA_TYPES[ext];
270	    if (!mt) {
271	      throw new Error(
272	        `upload(${basename(filePath)}): no mediaType known for "${ext}" — pass { mediaType } explicitly ` +
273	          `or add it to Pod.MEDIA_TYPES. Guessing octet-stream would misroute it (no vision, no transcription).`,
274	      );
275	    }
276	    const ref = await this.req('POST', '/api/uploads', {
277	      filename: filename ?? basename(filePath),
278	      mediaType: mt,
279	      data: bytes.toString('base64'),
280	    });
281	    return ref;
282	  }
283	
284	  // ── accounting ──────────────────────────────────────────────────────────
285	  /** Pod-global token/cost ledger — includes the DELEGATE tree, not just top-level turns. */
286	  sessionLedger = () => this.req('GET', '/api/session-ledger');
287	  /** The gateway's spend-window report, as the pod sees it. */
288	  budget = () => this.req('GET', '/api/budget');
289	
290	  // ── env / lifecycle ─────────────────────────────────────────────────────
291	  getEnv = () => this.req('GET', '/api/env');
292	  /** Restart the pod process (used by the auto-resume scenario). Pod exits ~100ms later. */
293	  restart = () => this.req('POST', '/api/restart', {}).catch(() => ({ ok: true }));
294	}
