452	/** Approve every consent card; leave other asks for the scenario. */
453	export const approveAllConsent = (descriptor) =>
454	  descriptor?.type === 'ConsentCard' ? true : undefined;
455	/** Deny every consent card (for the denial branch of the consent scenario). */
456	export const denyAllConsent = (descriptor) =>
457	  descriptor?.type === 'ConsentCard' ? false : undefined;
